// Dart imports:
import 'dart:io';

// Package imports:
import 'package:fimber/fimber.dart';
import 'package:mutex/mutex.dart';
import 'package:path/path.dart';
import 'package:riverpod_annotation/riverpod_annotation.dart';
import 'package:uuid/uuid.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure_code.dart';
import 'package:baseball_detector_flutter/data/models/local_video.dart';
import 'package:baseball_detector_flutter/data/result.dart';

part 'local_video_list_controller.g.dart';

/// A controller class that manages [LocalVideoStorage].
@Riverpod(keepAlive: true)
class LocalVideoListController extends _$LocalVideoListController {
  static final _logger = FimberLog('LocalVideoListController');
  static final _fc =
      failureCodeBuilder.category('CLVL'); // Controller-LocalVideoList

  bool _mounted = true;
  static final Mutex _mutex = Mutex();
  static final _deletedVideoIds = <String>{};

  @override
  AsyncValue<LocalVideoStorage> build() {
    _mounted = true;
    ref.onDispose(() => _mounted = false);

    _refreshLocalVideoList();
    return state;
  }

  void _refreshLocalVideoList() {
    state = const AsyncValue.loading();
    final localVideoStorage = LocalVideoStorage.getInstance();
    state = AsyncData(localVideoStorage);
  }

  Future<Result<Failure, void>> deleteVideo(String id,
      [bool deleteFile = true, bool rememberId = true]) async {
    final methodFc = _fc.category('DELV');
    // NOTE: [LocalVideoStorage.add] and [LocalVideoStorage.removeWhere] have their
    // own mutex. But this mutex is for race condition of [state].

    await _mutex.acquire();

    try {
      final localVideoStorage = LocalVideoStorage.getInstance();
      final localVideo = localVideoStorage.selectLocalVideoDataWhereTheIdIs(id);

      if (deleteFile) {
        await File(localVideo.absolutePath!).delete();
      }

      final storage = state.value!;

      state = const AsyncValue.loading();
      final isDeleted = await storage.removeById(id);
      if (isDeleted && rememberId) {
        // Remember a list of deleted videos to avoid making requests for videos
        // that no longer exist
        _deletedVideoIds.add(id);
      }
      if (!_mounted) return const Right(null);
      state = AsyncData(storage);
    } on StateError {
      // noop
    } catch (e, stackTrace) {
      _logger.e('unexpected error', ex: e, stacktrace: stackTrace);
      return Left(Failure.undefined(
        code: methodFc.position('001'),
        underlyingException: e,
      ));
    } finally {
      _mutex.release();
    }

    return const Right(null);
  }

  Future<LocalVideoData> addFile({
    required String sessionId,
    required String teamId,
    required String filePath,
    required int analyzeType,
    double? focalLengthIn35mmEquivalent,
    double? longsideAngleOfView,
    double? accX,
    double? accY,
    double? accZ,
    String? lens,
    String? cameraMode,
    double? focus,
    bool? isAutoFocus,
    double? zoom,
    double? iso,
    double? shutterSpeed,
    String? device,
  }) async {
    // NOTE: [LocalVideoStorage.add] and [LocalVideoStorage.removeWhere] have their
    // own mutex. But this mutex is for race condition of [state].

    await _mutex.acquire();

    try {
      final now = DateTime.now().toUtc();
      final id = const Uuid().v4();
      final relativeFilePath = relative(
        filePath,
        from: await LocalVideoData.getBaseDirectory(),
      );
      final data = LocalVideoData(
        id: id,
        sessionId: sessionId,
        teamId: teamId,
        path: relativeFilePath,
        absolutePath: filePath,
        analyzeType: analyzeType,
        createdAt: now,
        focalLengthIn35mmEquivalent: null,
        longsideAngleOfView: longsideAngleOfView,
        accX: accX,
        accY: accY,
        accZ: accZ,
        lens: lens,
        focus: focus,
        cameraMode: cameraMode,
        isAutoFocus: isAutoFocus,
        zoom: zoom,
        iso: iso,
        shutterSpeed: shutterSpeed,
        device: device,
      );

      final storage = state.value!;
      state = const AsyncValue.loading();
      await storage.add(data);
      if (!_mounted) return data;
      state = AsyncData(storage);

      return data;
    } catch (e) {
      rethrow;
    } finally {
      _mutex.release();
    }
  }

  Future<LocalVideoData> findVideoById(String id) async {
    await _mutex.acquire();

    try {
      final storage = state.value!;
      return storage.selectLocalVideoDataWhereTheIdIs(id);
    } on StateError {
      if (_deletedVideoIds.contains(id)) {
        throw DeletedVideoIdException(id);
      }
      rethrow;
    } catch (e) {
      rethrow;
    } finally {
      _mutex.release();
    }
  }
}

class DeletedVideoIdException implements Exception {
  final String id;

  const DeletedVideoIdException(this.id);
}

