    22→
    23→part 'resource_data_list_controller.g.dart';
    24→
    25→/// A controller class that manages [ResourceData.id] list.
    26→///
    27→/// Note: This controller just handles abstract repository.
    28→/// This means that the controller does not care
    29→/// the implementation of its repository is either remote DB or local cache.
    30→/// Therefore do not use anything related to a specific implementation of repository
    31→/// (e.g., the login state of the remote DB).
    32→@Riverpod(keepAlive: true)
    33→class ResourceDataListController extends _$ResourceDataListController {
    34→  static final _logger = FimberLog('ResourceDataListController');
    35→
    36→  static const _defaultPageSize = 20;
    37→
    38→  @override
    39→  Future<PagingData<ResourceData>> build({
    40→    required String teamId,
    41→    required String sessionId,
    42→  }) {
    43→    ref.watch(loginStateControllerProvider);
    44→    ref.watch(repositoryProvider);
    45→    ref.watch(userAccessibleContentsControllerProvider);
    46→    return fetch(
    47→      page: 0,
    48→      pageSize: _defaultPageSize,
    49→      teamId: teamId,
    50→      sessionId: sessionId,
    51→    );
    52→  }
    53→
    54→  Future<PagingData<ResourceData>> fetch({
    55→    required int page,
    56→    required int pageSize,
    57→    required String teamId,
    58→    required String sessionId,
    59→  }) async {
    60→    final res = await ref.read(repositoryProvider).getResources(
    61→          teamId: teamId,
    62→          sessionId: sessionId,
    63→          page: page,
    64→          pageSize: pageSize,
    65→        );
    66→
    67→    checkResultForMaintenance(ref, res);
    68→    if (res.hasLeft) throw res.left;
    69→
    70→    // ローカル動画とのマージ（ページごとに追加）
    71→    final mergedList = await _mergeLocalVideos(
    72→      res.right.resources,
    73→      sessionId,
    74→    );
    75→
    76→    return PagingData<ResourceData>(
    77→      items: mergedList,
    78→      page: page,
    79→      pageSize: pageSize,
    80→      total: res.right.total,
    81→      hasMore: mergedList.length + page * pageSize < res.right.total,
    82→    );
    83→  }
    84→
    85→  Future<void> loadNext() async {
    86→    final value = state.valueOrNull;
    87→    if (value == null || state.hasError || !value.hasMore) return;
    88→
    89→    state = AsyncLoading<PagingData<ResourceData>>().copyWithPrevious(state);
    90→
    91→    state = await state.guardPreservingPreviousOnError(() async {
    92→      final nextPage = value.page + 1;
    93→      final next = await fetch(
    94→        page: nextPage,
    95→        pageSize: value.pageSize,
    96→        teamId: teamId,
    97→        sessionId: sessionId,
    98→      );
    99→      return value.copyWith(
   100→        items: [...value.items, ...next.items],
   101→        page: nextPage,
   102→        hasMore: next.hasMore,
   103→        total: next.total,
   104→      );
   105→    });
   106→  }
   107→
   108→  void forceRefresh() {
   109→    state = AsyncLoading<PagingData<ResourceData>>();
   110→    ref.invalidateSelf();
   111→  }
   112→
   113→  Future<void> ensureMinimalItems(int minimalItems) async {
   114→    final value = state.valueOrNull;
   115→    final currentItems = value?.items.length ?? 0;
   116→    if (value == null || state.hasError || currentItems >= minimalItems) {
   117→      return;
   118→    }
   119→
   120→    state = AsyncLoading<PagingData<ResourceData>>().copyWithPrevious(state);
   121→    final pageSize = max(minimalItems - currentItems, _defaultPageSize);
   122→    state = await state.guardPreservingPreviousOnError(() async {
   123→      final next = await fetch(
   124→        page: 0,
   125→        pageSize: pageSize,
   126→        teamId: teamId,
   127→        sessionId: sessionId,
   128→      );
   129→      return value.copyWith(
   130→        items: next.items,
   131→        page: 0,
   132→        hasMore: next.hasMore,
   133→        total: next.total,
   134→      );
   135→    });
   136→  }
   137→
   138→  /// Merge remote [ResourceData] list and local videos, removing duplicates and logging warnings for unuploaded duplicates.
   139→  Future<List<ResourceData>> _mergeLocalVideos(
   140→    List<ResourceData> remoteVideos,
   141→    String sessionId,
   142→  ) async {
   143→    final mergedVideos = List<ResourceData>.from(remoteVideos);
   144→    final localVideoStorage = LocalVideoStorage.getInstance();
   145→    final localVideos = localVideoStorage.getLocalVideoList(sessionId);
   146→
   147→    // Find local videos that have the same id as remote videos
   148→    final remoteIds = Set<String>.from(mergedVideos.map((r) => r.id!));
   149→    final duplicated = localVideos.where((lv) => remoteIds.contains(lv.id));
   150→
   151→    // Remove local videos that have been uploaded at least once
   152→    final toRemove =
   153→        duplicated.where((lv) => lv.hasEverUploaded ?? false).toList();
   154→    if (toRemove.isNotEmpty) {
   155→      for (final lv in toRemove) {
   156→        await localVideoStorage.removeById(lv.id);
   157→        localVideos.remove(lv);
   158→      }
   159→      await localVideoStorage.save();
   160→      ref.invalidate(localVideoListControllerProvider);
   161→      _logger.i(
   162→        'Removed duplicated uploaded videos: ${toRemove.map((v) => v.id).join(', ')}',
   163→      );
   164→    }
   165→
   166→    // Warn for duplicated local videos that have never been uploaded
   167→    final warnNotUploaded =
   168→        duplicated.whereNot((lv) => lv.hasEverUploaded ?? false);
   169→    if (warnNotUploaded.isNotEmpty) {
   170→      _logger.w(
   171→        'Not uploaded duplicated videos detected: ${warnNotUploaded.map((v) => v.id).join(', ')}',
   172→      );
   173→    }
   174→
   175→    // Add remaining local videos as ResourceData
   176→    for (final lv in localVideos) {
   177→      mergedVideos.add(lv.transformToResourceData());
   178→    }
   179→    mergedVideos.sort((a, b) => a.createdAt!.compareTo(b.createdAt!));
   180→    return mergedVideos.reversed.toList();
   181→  }
   182→
   183→  // 削除・再解析などのメソッドはfetch/buildのstate更新に合わせて修正する必要あり
   184→  Future<Result<Failure, void>> deleteResourceData(
   185→    String sessionId,
   186→    String resourceId,
   187→  ) async {
   188→    final res = await ref.read(repositoryProvider).deleteResource(
   189→          sessionId: sessionId,
   190→          resourceId: resourceId,
   191→        );
   192→    checkResultForMaintenance(ref, res);
   193→    if (res.hasRight) {
   194→      if (state.value != null) {
   195→        final current = state.value!;
   196→        final newItems =
   197→            current.items.where((p) => p.id != resourceId).toList();
   198→        state = AsyncData(current.copyWith(items: newItems));
   199→      }
   200→    }
   201→    return res;
   202→  }
   203→
   204→  /// Edit pitch type for a specific ball and update the state
   205→  Future<Result<Failure, void>> editPitchType({
   206→    required String sessionId,
   207→    required String resourceId,
   208→    required int ballId,
   209→    required String? pitchTypeId,
   210→  }) async {
   211→    final res = await ref.read(repositoryProvider).editPitchType(
   212→          sessionId: sessionId,
   213→          resourceId: resourceId,
   214→          ballId: ballId,
   215→          pitchTypeId: pitchTypeId,
   216→        );
   217→
   218→    checkResultForMaintenance(ref, res);
   219→
   220→    // Update local state if API call succeeded
   221→    if (res.hasRight) {
   222→      updateSpecificPitchType(
   223→        resourceId: resourceId,
   224→        ball: res.right.ball,
   225→      );
   226→    }
   227→
   228→    return res;
   229→  }
   230→
   231→  // Update the pitch type of the specific resourceData
   232→  void updateSpecificPitchType({
   233→    required String resourceId,
   234→    required Ball ball,
   235→  }) {
   236→    if (state.value != null) {
   237→      final current = state.value!;
   238→      final newItems = current.items
   239→          .map((resourceData) => resourceData.id == resourceId
   240→              ? resourceData.copyWith(
   241→                  ballInfoList: resourceData.ballInfoList
   242→                      ?.map((ballInfo) => ballInfo.ball.id == ball.id
   243→                          ? ballInfo.copyWith(ball: ball)
   244→                          : ballInfo)
   245→                      .toList())
   246→              : resourceData)
   247→          .toList();
   248→      state = AsyncData(current.copyWith(items: newItems));
   249→    }
   250→  }
   251→
   252→  // Remove a ball from the specific resourceData
   253→  void removeBallFromResource({
   254→    required String resourceId,
   255→    required int ballId,
   256→  }) {
   257→    if (state.value != null) {
   258→      final current = state.value!;
   259→      final newItems = current.items
   260→          .map((resourceData) => resourceData.id == resourceId
   261→              ? resourceData.copyWith(
