// Dart imports:
import 'dart:math';

// Package imports:
import 'package:collection/collection.dart';
import 'package:fimber/fimber.dart';
import 'package:riverpod_annotation/riverpod_annotation.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/check_result.dart';
import 'package:baseball_detector_flutter/controllers/local_video_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/login_state_controller.dart';
import 'package:baseball_detector_flutter/controllers/user_accessible_contents_controller.dart';
import 'package:baseball_detector_flutter/controllers/utils/paging_notifier_mixin.dart';
import 'package:baseball_detector_flutter/data/models/ball.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/data/models/local_video.dart';
import 'package:baseball_detector_flutter/data/models/paging_data.dart';
import 'package:baseball_detector_flutter/data/models/resource.dart';
import 'package:baseball_detector_flutter/data/result.dart';
import 'package:baseball_detector_flutter/providers/repository_provider.dart';

part 'resource_data_list_controller.g.dart';

/// A controller class that manages [ResourceData.id] list.
///
/// Note: This controller just handles abstract repository.
/// This means that the controller does not care
/// the implementation of its repository is either remote DB or local cache.
/// Therefore do not use anything related to a specific implementation of repository
/// (e.g., the login state of the remote DB).
@Riverpod(keepAlive: true)
class ResourceDataListController extends _$ResourceDataListController {
  static final _logger = FimberLog('ResourceDataListController');

  static const _defaultPageSize = 20;

  @override
  Future<PagingData<ResourceData>> build({
    required String teamId,
    required String sessionId,
  }) {
    ref.watch(loginStateControllerProvider);
    ref.watch(repositoryProvider);
    ref.watch(userAccessibleContentsControllerProvider);
    return fetch(
      page: 0,
      pageSize: _defaultPageSize,
      teamId: teamId,
      sessionId: sessionId,
    );
  }

  Future<PagingData<ResourceData>> fetch({
    required int page,
    required int pageSize,
    required String teamId,
    required String sessionId,
  }) async {
    final res = await ref.read(repositoryProvider).getResources(
          teamId: teamId,
          sessionId: sessionId,
          page: page,
          pageSize: pageSize,
        );

    checkResultForMaintenance(ref, res);
    if (res.hasLeft) throw res.left;

    // ローカル動画とのマージ（ページごとに追加）
    final mergedList = await _mergeLocalVideos(
      res.right.resources,
      sessionId,
    );

    return PagingData<ResourceData>(
      items: mergedList,
      page: page,
      pageSize: pageSize,
      total: res.right.total,
      hasMore: mergedList.length + page * pageSize < res.right.total,
    );
  }

  Future<void> loadNext() async {
    final value = state.valueOrNull;
    if (value == null || state.hasError || !value.hasMore) return;

    state = AsyncLoading<PagingData<ResourceData>>().copyWithPrevious(state);

    state = await state.guardPreservingPreviousOnError(() async {
      final nextPage = value.page + 1;
      final next = await fetch(
        page: nextPage,
        pageSize: value.pageSize,
        teamId: teamId,
        sessionId: sessionId,
      );
      return value.copyWith(
        items: [...value.items, ...next.items],
        page: nextPage,
        hasMore: next.hasMore,
        total: next.total,
      );
    });
  }

  void forceRefresh() {
    state = AsyncLoading<PagingData<ResourceData>>();
    ref.invalidateSelf();
  }

  Future<void> ensureMinimalItems(int minimalItems) async {
    final value = state.valueOrNull;
    final currentItems = value?.items.length ?? 0;
    if (value == null || state.hasError || currentItems >= minimalItems) {
      return;
    }

    state = AsyncLoading<PagingData<ResourceData>>().copyWithPrevious(state);
    final pageSize = max(minimalItems - currentItems, _defaultPageSize);
    state = await state.guardPreservingPreviousOnError(() async {
      final next = await fetch(
        page: 0,
        pageSize: pageSize,
        teamId: teamId,
        sessionId: sessionId,
      );
      return value.copyWith(
        items: next.items,
        page: 0,
        hasMore: next.hasMore,
        total: next.total,
      );
    });
  }

  /// Merge remote [ResourceData] list and local videos, removing duplicates and logging warnings for unuploaded duplicates.
  Future<List<ResourceData>> _mergeLocalVideos(
    List<ResourceData> remoteVideos,
    String sessionId,
  ) async {
    final mergedVideos = List<ResourceData>.from(remoteVideos);
    final localVideoStorage = LocalVideoStorage.getInstance();
    final localVideos = localVideoStorage.getLocalVideoList(sessionId);

    // Find local videos that have the same id as remote videos
    final remoteIds = Set<String>.from(mergedVideos.map((r) => r.id!));
    final duplicated = localVideos.where((lv) => remoteIds.contains(lv.id));

    // Remove local videos that have been uploaded at least once
    final toRemove =
        duplicated.where((lv) => lv.hasEverUploaded ?? false).toList();
    if (toRemove.isNotEmpty) {
      for (final lv in toRemove) {
        await localVideoStorage.removeById(lv.id);
        localVideos.remove(lv);
      }
      await localVideoStorage.save();
      ref.invalidate(localVideoListControllerProvider);
      _logger.i(
        'Removed duplicated uploaded videos: ${toRemove.map((v) => v.id).join(', ')}',
      );
    }

    // Warn for duplicated local videos that have never been uploaded
    final warnNotUploaded =
        duplicated.whereNot((lv) => lv.hasEverUploaded ?? false);
    if (warnNotUploaded.isNotEmpty) {
      _logger.w(
        'Not uploaded duplicated videos detected: ${warnNotUploaded.map((v) => v.id).join(', ')}',
      );
    }

    // Add remaining local videos as ResourceData
    for (final lv in localVideos) {
      mergedVideos.add(lv.transformToResourceData());
    }
    mergedVideos.sort((a, b) => a.createdAt!.compareTo(b.createdAt!));
    return mergedVideos.reversed.toList();
  }

  // 削除・再解析などのメソッドはfetch/buildのstate更新に合わせて修正する必要あり
  Future<Result<Failure, void>> deleteResourceData(
    String sessionId,
    String resourceId,
  ) async {
    final res = await ref.read(repositoryProvider).deleteResource(
          sessionId: sessionId,
          resourceId: resourceId,
        );
    checkResultForMaintenance(ref, res);
    if (res.hasRight) {
      if (state.value != null) {
        final current = state.value!;
        final newItems =
            current.items.where((p) => p.id != resourceId).toList();
        state = AsyncData(current.copyWith(items: newItems));
      }
    }
    return res;
  }

  /// Edit pitch type for a specific ball and update the state
  Future<Result<Failure, void>> editPitchType({
    required String sessionId,
    required String resourceId,
    required int ballId,
    required String? pitchTypeId,
  }) async {
    final res = await ref.read(repositoryProvider).editPitchType(
          sessionId: sessionId,
          resourceId: resourceId,
          ballId: ballId,
          pitchTypeId: pitchTypeId,
        );

    checkResultForMaintenance(ref, res);

    // Update local state if API call succeeded
    if (res.hasRight) {
      updateSpecificPitchType(
        resourceId: resourceId,
        ball: res.right.ball,
      );
    }

    return res;
  }

  // Update the pitch type of the specific resourceData
  void updateSpecificPitchType({
    required String resourceId,
    required Ball ball,
  }) {
    if (state.value != null) {
      final current = state.value!;
      final newItems = current.items
          .map((resourceData) => resourceData.id == resourceId
              ? resourceData.copyWith(
                  ballInfoList: resourceData.ballInfoList
                      ?.map((ballInfo) => ballInfo.ball.id == ball.id
                          ? ballInfo.copyWith(ball: ball)
                          : ballInfo)
                      .toList())
              : resourceData)
          .toList();
      state = AsyncData(current.copyWith(items: newItems));
    }
  }

  // Remove a ball from the specific resourceData
  void removeBallFromResource({
    required String resourceId,
    required int ballId,
  }) {
    if (state.value != null) {
      final current = state.value!;
      final newItems = current.items
          .map((resourceData) => resourceData.id == resourceId
              ? resourceData.copyWith(
                  ballInfoList: resourceData.ballInfoList
                      ?.where((ballInfo) => ballInfo.ball.id != ballId)
                      .toList())
              : resourceData)
          .toList();
      state = AsyncData(current.copyWith(items: newItems));
    }
  }

  /// Update a specific resource data in the current list
  void updateResourceData(ResourceData updatedResource) {
    if (state.value != null) {
      final current = state.value!;
      final newItems = current.items
          .map((resourceData) => resourceData.id == updatedResource.id
              ? updatedResource
              : resourceData)
          .toList();
      state = AsyncData(current.copyWith(items: newItems));
    }
  }
}

# Bug Analysis: "Bad state: No element" Exception in ResourceUploadDialog

## 概要

`ResourceUploadDialog` でローカルビデオのアップロードを試行した際に、`Bad state: No element` 例外が発生する問題の原因調査と修正案。

## エラー情報

### エラーメッセージ

```
UNHANDLED EXCEPTION:
Bad state: No element
    #0      List.first (dart:core-patch/growable_array.dart:352)
    #1      LocalVideoStorage.selectLocalVideoDataWhereTheIdIs (package:baseball_detector_flutter/data/models/local_video.dart:212)
    #2      LocalVideoListController.findVideoById (package:baseball_detector_flutter/controllers/local_video_list_controller.dart:166)
    <asynchronous suspension>
    #3      ResourceUploadDialog.build.<anonymous closure> (package:baseball_detector_flutter/views/pages/home/sessions/session_details/resource_details/components/resource_upload_dialog.dart:33)
```

### 発生箇所

- **起点**: `resource_upload_dialog.dart:33`
- **問題のメソッド**: `local_video.dart:207` の `selectLocalVideoDataWhereTheIdIs`

## 根本原因

### 1. コードレベルの問題

`LocalVideoStorage.selectLocalVideoDataWhereTheIdIs` メソッドが、存在しない ID に対して安全でない実装になっている：

```dart
// local_video.dart:206-208
LocalVideoData selectLocalVideoDataWhereTheIdIs(String id) {
  return localVideoList.where((element) => element.id == id).toList().first;
}
```

**問題点:**
- ID に一致する要素が存在しない場合、空のリストに対して `.first` を呼び出す
- `.first` は空のリストに対して `StateError: No element` を投げる
- null チェックや例外ハンドリングが存在しない

### 2. データ整合性の問題

`ResourceData` (サーバー側のリソース情報) と `LocalVideoData` (ローカルの動画ファイル情報) の同期が取れていない状況で発生：

- `ResourceData.statusType` が `onLocalStorage` (ローカルにのみ存在)
- しかし実際には対応する `LocalVideoData` が既に削除されている
- UI は古い状態を表示し続けている

### 3. エラーハンドリングの不足

`LocalVideoListController.findVideoById` では部分的なエラーハンドリングが実装されているが、呼び出し側でキャッチされていない：

```dart
// local_video_list_controller.dart:155-171
Future<LocalVideoData> findVideoById(String id) async {
  await _mutex.acquire();
  try {
    final storage = state.value!;
    return storage.selectLocalVideoDataWhereTheIdIs(id);
  } on StateError {
    if (_deletedVideoIds.contains(id)) {
      throw DeletedVideoIdException(id);  // この例外がキャッチされていない
    }
    rethrow;
  } catch (e) {
    rethrow;
  } finally {
    _mutex.release();
  }
}
```

## 発生する具体的なシナリオ

### シナリオ 1: ユーザーによる手動削除後の再試行

**ステップ:**

1. ユーザーが動画を録画 → `LocalVideoData` と `ResourceData` が作成される
2. ネットワーク不良などでアップロードに失敗 → `ResourceData.statusType` が `onLocalStorage` のまま
3. ユーザーが「録画リスト」画面に移動し、容量削減のためにローカル動画を削除
   - `LocalVideoData` が削除される
   - しかし `ResourceData` は削除されず、`onLocalStorage` 状態のまま残る
4. ユーザーがリソース詳細画面に戻る
5. スナックバーに「ローカルストレージ上にあります / 再試行」ボタンが表示される
6. ユーザーが「再試行」ボタンをタップ
7. `ResourceUploadDialog` が開き、アップロードボタンをタップ
8. **エラー発生**: 削除済みの ID で `findVideoById` を呼び出し → 例外

### シナリオ 2: アプリ再起動後のデータ不整合

**ステップ:**

1. ユーザーが動画を録画し、アップロード中にアプリがクラッシュまたは強制終了
2. 再起動時に `LocalVideoStorage.loadSingleton()` が実行されるが、ファイルシステムとの整合性チェックが不十分
3. 動画ファイルが物理的に削除されているが、`LocalVideoData` のエントリが残っている（または逆）
4. ユーザーがアップロードを試行
5. **エラー発生**: 存在しない ID で検索

### シナリオ 3: 複数デバイス間での競合（将来的なリスク）

**ステップ:**

1. ユーザーが同じアカウントで複数デバイスを使用
2. デバイス A でローカル動画を削除
3. デバイス B で同期が不完全なまま、削除済み動画のアップロードを試行
4. **エラー発生**: デバイス B のローカルストレージに存在しない ID を検索

### シナリオ 4: アップロード完了後の状態更新遅延

**ステップ:**

1. ユーザーが動画をアップロード
2. アップロード完了後、`LocalVideoData` は削除されるが、`ResourceData` の状態更新が遅延
3. ユーザーが素早く画面を再表示し、まだ `onLocalStorage` 状態のリソースを見る
4. 「再試行」ボタンをタップ
5. **エラー発生**: 既に削除された ID で検索

## 修正案

### 修正案 1: ResourceUploadDialog でエラーハンドリングを追加 ⭐ 推奨

**対象ファイル:** `lib/views/pages/home/sessions/session_details/resource_details/components/resource_upload_dialog.dart`

**変更内容:**

```dart
aboveButtonAction: (context) async {
  try {
    final localVideoData = await ref
        .read(localVideoListControllerProvider.notifier)
        .findVideoById(resource.id!);

    // Add to upload queue
    ref.read(uploadQueueProvider).addUploadTask(localVideoData);

    // Invalidate resource data list
    ref.invalidate(
      resourceDataListControllerProvider(
        teamId: resource.teamId!,
        sessionId: resource.sessionId!,
      ),
    );
    onSucceeded?.call();
    if (context.mounted) {
      Navigator.of(context).pop(); // pop the dialog.
    }
  } on DeletedVideoIdException catch (_) {
    // ビデオが既に削除されている場合
    if (context.mounted) {
      Navigator.of(context).pop(); // pop the dialog
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(context.l10n.error_video_already_deleted),
          backgroundColor: Colors.red,
        ),
      );
    }
    onFailed?.call();
  } on StateError catch (_) {
    // ビデオが見つからない場合
    if (context.mounted) {
      Navigator.of(context).pop(); // pop the dialog
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(context.l10n.error_video_not_found),
          backgroundColor: Colors.red,
        ),
      );
    }
    onFailed?.call();
  } catch (e) {
    // その他の予期しないエラー
    if (context.mounted) {
      Navigator.of(context).pop(); // pop the dialog
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(context.l10n.error_unexpected),
          backgroundColor: Colors.red,
        ),
      );
    }
    onFailed?.call();
  }
},
```

**メリット:**
- UI レイヤーで適切なエラーハンドリング
- ユーザーに分かりやすいエラーメッセージを表示
- 既存のコードへの影響が最小限

**必要な追加作業:**
- `l10n/app_ja.arb` と `l10n/app_en.arb` にエラーメッセージを追加
  - `error_video_already_deleted`
  - `error_video_not_found`
  - `error_unexpected`

### 修正案 2: selectLocalVideoDataWhereTheIdIs を安全にする ⭐ 推奨

**対象ファイル:** `lib/data/models/local_video.dart`

**変更内容:**

```dart
// Option A: Nullable を返す
LocalVideoData? selectLocalVideoDataWhereTheIdIs(String id) {
  final results = localVideoList.where((element) => element.id == id).toList();
  return results.isEmpty ? null : results.first;
}

// Option B: firstOrNull を使用（Dart 3.0+）
LocalVideoData? selectLocalVideoDataWhereTheIdIs(String id) {
  return localVideoList
      .where((element) => element.id == id)
      .firstOrNull;
}
```

**影響範囲の確認が必要:**
このメソッドを呼び出している全ての箇所で null チェックが必要：
- `LocalVideoListController.findVideoById`
- `LocalVideoListController.deleteVideo`
- その他の呼び出し箇所

**メリット:**
- データレイヤーでの防御的プログラミング
- 将来的なバグの予防
- より明示的な API

**デメリット:**
- 既存コードへの影響が大きい
- 全ての呼び出し箇所の修正が必要

### 修正案 3: ResourceData の状態を事前チェック

**対象ファイル:** `lib/views/pages/home/sessions/session_details/resource_details/components/resource_details_snackbar.dart`

**変更内容:**

```dart
// ResourceUploadDialog を表示する前にチェック
_buildTappableText(
  context.l10n.resource_details_page__try_again,
  () async {
    // 事前チェック: ローカルビデオが実際に存在するか確認
    try {
      await ref
          .read(localVideoListControllerProvider.notifier)
          .findVideoById(resource.id!);

      // 存在する場合のみダイアログを表示
      _showResourceDialog(
