        ResourceUploadDialog(
          resource: resource,
          onSucceeded: rerender,
        ),
      );
    } on DeletedVideoIdException catch (_) {
      // ビデオが削除されている場合、エラーメッセージを表示
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(context.l10n.error_video_already_deleted),
          backgroundColor: Colors.red,
        ),
      );
    } on StateError catch (_) {
      // ビデオが見つからない場合
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(context.l10n.error_video_not_found),
          backgroundColor: Colors.red,
        ),
      );
    }
  },
),
```

**メリット:**
- ダイアログを開く前に問題を検出
- より良いユーザー体験

**デメリット:**
- 2 回 `findVideoById` を呼び出すことになる（事前チェックとダイアログ内）
- 競合状態のリスクは残る（チェック後、ダイアログ表示前に削除される可能性）

### 修正案 4: LocalVideoStorage.loadSingleton でファイル存在チェック

**対象ファイル:** `lib/data/models/local_video.dart`

**変更内容:**

```dart
static Future<void> loadSingleton() async {
  final dataPath = await _getLocalVideoDataPath();
  final file = File(dataPath);
  if (await file.exists()) {
    final buf = await file.readAsString();
    try {
      _singletonInstance = LocalVideoStorage._fromJson(json.decode(buf));

      final dirPath = await LocalVideoData.getBaseDirectory();
      final validVideos = <LocalVideoData>[];

      for (final localVideoData in _singletonInstance.localVideoList) {
        localVideoData._fillFields(dirPath);

        // ファイルが実際に存在するかチェック
        if (localVideoData.absolutePath != null) {
          final videoFile = File(localVideoData.absolutePath!);
          if (await videoFile.exists()) {
            validVideos.add(localVideoData);
          } else {
            // ファイルが存在しない場合はログに記録
            print('Warning: Video file not found: ${localVideoData.absolutePath}');
          }
        }
      }

      // 存在するファイルのみをリストに保持
      _singletonInstance.localVideoList = validVideos;

      // クリーンアップ後のデータを保存
      await _singletonInstance.save();
    } catch (e) {
      // noop
    }
  }
}
```

**メリット:**
- アプリ起動時にデータの整合性を保証
- 孤立した（ファイルが削除された）エントリを自動的にクリーンアップ

**デメリット:**
- 起動時のパフォーマンスへの影響
- 大量の動画がある場合、チェックに時間がかかる
- 意図的にファイルを別の場所に移動した場合も削除される

## 推奨される実装方針

### 優先度 1（必須）: 修正案 1

`ResourceUploadDialog` でエラーハンドリングを追加し、ユーザーに適切なフィードバックを提供する。これにより即座にクラッシュを防ぐことができる。

### 優先度 2（推奨）: 修正案 2

`selectLocalVideoDataWhereTheIdIs` を nullable にして、データレイヤーでの安全性を向上させる。ただし、影響範囲の調査と全ての呼び出し箇所の修正が必要。

### 優先度 3（オプション）: 修正案 4

アプリ起動時にデータの整合性をチェックし、孤立したエントリをクリーンアップする。ただし、パフォーマンスへの影響を考慮する必要がある。

## 追加の改善提案

### 1. データ同期メカニズムの強化

`LocalVideoData` が削除されたときに、対応する `ResourceData` の状態も更新するメカニズムを追加：

```dart
// LocalVideoListController.deleteVideo 内
